class Solution:

def max_of_elements(self, arr):
	return max(arr)

def counting_sort(self, arr, place):
	mp = Counter()
	for num in arr:
		tmp[num % 10] += 1
	arr[:] = sorted(arr, key=lambda x: (x // place) % 10)
	return arr

def radix_sort(self, arr):
	max_n = max(arr)
	place = 1
	while max_n >= 0:
		arr = counting_sort(arr, place)
		place *= 10
		max_n //= place
		print("Radix sort array: ", end="")
